{
  "schema_name": "eywa_node_response",
  "schema_version": "v1",
  "orchestration_decision": "delegate",
  "decision_notes": "The problem requires a combination of spatial pattern matching, probabilistic inference under noise, and optimal experimental design for cost minimization.",
  "helpers": [
    {
      "label": "spatial_state_representation",
      "instructions": "Define a mathematical representation for the grid state that tracks the probability of each cell being part of an oil field. Incorporate the known polyomino shapes as a set of possible relative coordinate offsets. Maintain a belief state that maps each cell to a probability distribution over the possible placements and orientations of the polyominoes."
    },
    {
      "label": "probabilistic_query_modeling",
      "instructions": "Develop a likelihood function that models the noisy aggregate queries. Given a set of queried cells, calculate the probability of receiving a specific aggregate result (e.g., a count or a binary signal) based on the current belief state of oil cell locations and the known noise characteristics of the sensor."
    },
    {
      "label": "information_gain_optimization",
      "instructions": "Implement an acquisition function to select the next probing action (drilling or aggregate query). Use an information-theoretic approach, such as maximizing expected information gain or minimizing expected entropy, to identify which query location or set of cells most effectively reduces the uncertainty in the current belief state regarding the polyomino placements."
    },
    {
      "label": "cost_benefit_decision_logic",
      "instructions": "Create a decision engine that balances the cost of a probe against the expected reduction in uncertainty. This component must decide when to stop probing and transition to the final guess phase by comparing the expected cost of further queries against the potential penalty of an incorrect final answer."
    },
    {
      "label": "final_inference_and_recovery",
      "instructions": "Perform a maximum a posteriori (MAP) estimation to identify the most likely configuration of polyominoes given all collected query data. Once the configuration is determined, extract the full set of coordinates representing the oil-containing cells to form the final answer."
    }
  ],
  "synthesis_brief": "The parent should use the spatial representation to maintain the belief state, iteratively call the information gain and cost-benefit components to select optimal probes, update the belief state using the probabilistic query model after each observation, and finally trigger the inference component to output the most probable oil cell locations once the cost-benefit threshold is met."
}

